import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

const BusList = () => {
  const [buses, setBuses] = useState([]);
  const [searchData, setSearchData] = useState(null);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    const storedSearchData = localStorage.getItem('searchData');
    if (storedSearchData) {
      const data = JSON.parse(storedSearchData);
      setSearchData(data);
      generateMockBuses(data);
    } else {
      navigate('/search');
    }
  }, [navigate]);

  const generateMockBuses = (search) => {
    setLoading(true);

    // Mock bus data generation
    const mockBuses = [
      {
        id: 1,
        busName: 'Express Travels',
        busType: 'AC Sleeper',
        departure: '08:00 AM',
        arrival: '02:00 PM',
        duration: '6h 00m',
        price: 450,
        availableSeats: 12,
        totalSeats: 40,
        rating: 4.2
      },
      {
        id: 2,
        busName: 'Royal Bus Service',
        busType: 'Non AC Seater',
        departure: '10:30 AM',
        arrival: '05:30 PM',
        duration: '7h 00m',
        price: 280,
        availableSeats: 8,
        totalSeats: 45,
        rating: 3.8
      },
      {
        id: 3,
        busName: 'Super Deluxe',
        busType: 'AC Seater',
        departure: '02:00 PM',
        arrival: '09:00 PM',
        duration: '7h 00m',
        price: 350,
        availableSeats: 15,
        totalSeats: 35,
        rating: 4.5
      },
      {
        id: 4,
        busName: 'Night Rider',
        busType: 'AC Sleeper',
        departure: '09:00 PM',
        arrival: '03:00 AM',
        duration: '6h 00m',
        price: 520,
        availableSeats: 5,
        totalSeats: 30,
        rating: 4.0
      },
      {
        id: 5,
        busName: 'Economy Express',
        busType: 'Non AC Sleeper',
        departure: '11:00 PM',
        arrival: '06:00 AM',
        duration: '7h 00m',
        price: 320,
        availableSeats: 20,
        totalSeats: 42,
        rating: 3.5
      }
    ];

    setTimeout(() => {
      setBuses(mockBuses);
      setLoading(false);
    }, 1000);
  };

  const handleSelectBus = (bus) => {
    localStorage.setItem('selectedBus', JSON.stringify(bus));
    navigate('/seats');
  };

  const handleBack = () => {
    navigate('/search');
  };

  if (loading) {
    return (
      <div className="card" style={{ textAlign: 'center', padding: '50px' }}>
        <p>Loading buses...</p>
      </div>
    );
  }

  return (
    <div>
      <div className="card">
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
          <h2>Available Buses</h2>
          <button className="btn btn-secondary" onClick={handleBack}>
            ← Back to Search
          </button>
        </div>

        {searchData && (
          <div style={{ background: '#f8f9fa', padding: '15px', borderRadius: '5px', marginBottom: '20px' }}>
            <strong>Route:</strong> {searchData.source} → {searchData.destination} | 
            <strong> Date:</strong> {new Date(searchData.date).toLocaleDateString()}
          </div>
        )}

        {buses.length === 0 ? (
          <p>No buses available for this route on the selected date.</p>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
            {buses.map(bus => (
              <div key={bus.id} className="card" style={{ border: '1px solid #ddd' }}>
                <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr 1fr 1fr auto', gap: '20px', alignItems: 'center' }}>
                  <div>
                    <h3 style={{ margin: '0 0 5px 0' }}>{bus.busName}</h3>
                    <p style={{ margin: '0', color: '#666', fontSize: '14px' }}>{bus.busType}</p>
                    <div style={{ display: 'flex', gap: '10px', marginTop: '5px' }}>
                      <span style={{ fontSize: '12px', color: '#666' }}>⭐ {bus.rating}</span>
                      <span style={{ fontSize: '12px', color: '#666' }}>
                        {bus.availableSeats}/{bus.totalSeats} seats
                      </span>
                    </div>
                  </div>

                  <div>
                    <div style={{ fontWeight: 'bold' }}>{bus.departure}</div>
                    <div style={{ fontSize: '12px', color: '#666' }}>Departure</div>
                  </div>

                  <div>
                    <div style={{ fontWeight: 'bold' }}>{bus.arrival}</div>
                    <div style={{ fontSize: '12px', color: '#666' }}>Arrival</div>
                  </div>

                  <div>
                    <div style={{ fontWeight: 'bold', color: '#007bff' }}>₹{bus.price}</div>
                    <div style={{ fontSize: '12px', color: '#666' }}>{bus.duration}</div>
                  </div>

                  <div>
                    <button
                      className="btn"
                      onClick={() => handleSelectBus(bus)}
                      disabled={bus.availableSeats === 0}
                      style={{ 
                        opacity: bus.availableSeats === 0 ? 0.5 : 1,
                        cursor: bus.availableSeats === 0 ? 'not-allowed' : 'pointer'
                      }}
                    >
                      {bus.availableSeats === 0 ? 'Sold Out' : 'Select Seats'}
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default BusList;
